import { useMemo } from 'react';

// Fuzzy search implementation
// Based on the Fuse.js algorithm but simplified for our needs

export function fuzzySearch(query, text) {
  if (!query || !text) return false;
  
  const queryLower = query.toLowerCase();
  const textLower = text.toLowerCase();
  
  // Simple contains check for short queries
  if (queryLower.length <= 3) {
    return textLower.includes(queryLower);
  }
  
  // Fuzzy match for longer queries
  let queryIndex = 0;
  let textIndex = 0;
  let score = 0;
  let consecutive = 0;
  
  while (queryIndex < queryLower.length && textIndex < textLower.length) {
    if (queryLower[queryIndex] === textLower[textIndex]) {
      score += 1 + consecutive * 0.5; // Bonus for consecutive matches
      consecutive += 1;
      queryIndex += 1;
    } else {
      consecutive = 0;
    }
    textIndex += 1;
  }
  
  // Require at least 60% of query characters to match
  const matchRatio = score / queryLower.length;
  return matchRatio >= 0.6;
}

// Hook for fuzzy search with memoization
export function useFuzzySearch(query, items, keys) {
  return useMemo(() => {
    if (!query) return items;
    
    return items.filter(item => {
      // Check all specified keys for matches
      for (const key of keys) {
        const value = item[key];
        if (!value) continue;
        
        // Handle array values
        if (Array.isArray(value)) {
          if (value.some(v => fuzzySearch(query, v))) {
            return true;
          }
        }
        // Handle string values
        else if (typeof value === 'string') {
          if (fuzzySearch(query, value)) {
            return true;
          }
        }
      }
      return false;
    });
  }, [query, items, keys]);
}