import { useState, useMemo, useEffect, useRef } from "react";
import { useSearchParams, Link, useNavigate } from "react-router-dom";
import {
  Search, TrendingUp, TrendingDown, Minus, AlertTriangle, Loader2, Star, GitCompare, X, ArrowUpRight, Flame, Sparkles, ShieldCheck, Shield, ShieldAlert, ShieldX, Skull, Clock,
} from "lucide-react";
import { CMD_KEY_CHIP } from "@/lib/platform";
import Header from "@/components/landing/Header";
import Footer from "@/components/landing/Footer";
import { useMarket, useSellerItems } from "@/lib/MarketContext";
import { useCompare, useWatchlists } from "@/lib/useFavorites";
import { fmt, fmtTime } from "@/lib/parseItem";
import { Reveal } from "@/components/landing/motion";
import { toast } from "sonner";
import { openItem } from "@/components/landing/DetailDrawer";
import StaleDataBanner from "@/components/landing/StaleDataBanner";
import OfflineBanner from "@/components/landing/OfflineBanner";
import RecentlyViewed from "@/components/landing/RecentlyViewed";
import ItemName from "@/components/landing/ItemName";
import { useLocalStorageState } from "@/lib/useLocalStorageState";
import { fuzzySearch } from "@/lib/useFuzzySearch";
import FreshnessPill from "@/components/landing/FreshnessPill";

const PAGE_SIZE = 50;

// A "deal" is the current median sitting in the bottom 20% of its
// IQR, AND the IQR has at least 10% spread. The second check matters:
// a stable 700k-priced item with iqrLow=700k, iqrHigh=700k is NOT a
// Stricter deal / overpriced rules: IQR must be at least 25% wide AND
// the median must sit in the bottom/top 10% of that IQR. The old 10%
// spread + 20th-percentile rule was firing on too many items whose IQR
// was only marginally wide, making the badges feel noisy.
const MIN_SPREAD = 0.25;
const DEAL_PERCENTILE = 0.10;
const OVERPRICED_PERCENTILE = 0.90;
const isDeal = (r) => {
  if (r.median <= 0 || r.iqrLow <= 0 || r.iqrHigh <= r.iqrLow) return false;
  const spread = (r.iqrHigh - r.iqrLow) / r.iqrLow;
  if (spread < MIN_SPREAD) return false;
  return (r.median - r.iqrLow) / (r.iqrHigh - r.iqrLow) <= DEAL_PERCENTILE;
};
const isOverpriced = (r) => {
  if (r.median <= 0 || r.iqrLow <= 0 || r.iqrHigh <= r.iqrLow) return false;
  const spread = (r.iqrHigh - r.iqrLow) / r.iqrLow;
  if (spread < MIN_SPREAD) return false;
  return (r.median - r.iqrLow) / (r.iqrHigh - r.iqrLow) >= OVERPRICED_PERCENTILE;
};
// 0 = at IQR low, 1 = at IQR high. Returns 0.5 for items with no
// meaningful spread (used to push them to the bottom of deal-sorted lists).
const dealScore = (r) => {
  if (r.median <= 0 || r.iqrLow <= 0 || r.iqrHigh <= r.iqrLow) return 0.5;
  const spread = (r.iqrHigh - r.iqrLow) / r.iqrLow;
  if (spread < MIN_SPREAD) return 0.5;
  return (r.median - r.iqrLow) / (r.iqrHigh - r.iqrLow);
};

const ConfDot = ({ conf }) => {
  const map = { high: "bg-emerald-400", good: "bg-lime-400", fair: "bg-amber-400", low: "bg-orange-400", unreliable: "bg-zinc-600" };
  return <span className={`inline-block w-1.5 h-1.5 rounded-full ${map[conf] || "bg-zinc-600"}`}></span>;
};

const TrendIcon = ({ trend }) => {
  if (trend === "up") return <TrendingUp className="w-3.5 h-3.5 text-emerald-400" />;
  if (trend === "down") return <TrendingDown className="w-3.5 h-3.5 text-red-400" />;
  return <Minus className="w-3.5 h-3.5 text-zinc-500" />;
};

const DEAL_RADAR = [
  { id: "trusted",  label: "High confidence", icon: ShieldCheck, color: "emerald", filter: (r) => r.confidence === "high" || r.confidence === "good" },
  { id: "rising",   label: "Rising fast",     icon: TrendingUp,  color: "emerald", filter: (r) => r.trend === "up" },
  { id: "falling",  label: "Falling",         icon: TrendingDown, color: "red",     filter: (r) => r.trend === "down" },
  { id: "deals",    label: "Deals",           icon: Flame,        color: "amber",   filter: isDeal },
  { id: "overpriced", label: "Overpriced",    icon: Skull,        color: "red",     filter: isOverpriced },
  { id: "cheap",    label: "Under 100K",      icon: Flame,        color: "amber",   filter: (r) => r.median > 0 && r.median < 100_000 },
  { id: "expensive",label: "Over 10M",        icon: Sparkles,     color: "amber",   filter: (r) => r.median >= 10_000_000 },
];

export default function ListingsPage() {
  const { market, loading, error, sellers } = useMarket();
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();
  const sellerFilter = searchParams.get("seller") || "";
  const channel = searchParams.get("channel") || "";
  const radar = searchParams.get("r") || "";

  const [q, setQ] = useState("");
  const [category, setCategory] = useLocalStorageState("castia.listings.category", "");
  const [confidence, setConfidence] = useLocalStorageState("castia.listings.confidence", "");
  const [priceRange, setPriceRange] = useLocalStorageState("castia.listings.priceRange", [0, 0]);
  const [sortKey, setSortKey] = useLocalStorageState("castia.listings.sortKey", "lastSeen");
  const [sortDir, setSortDir] = useLocalStorageState("castia.listings.sortDir", "desc");
  const [page, setPage] = useState(1);
  const [cursor, setCursor] = useState(0);
const searchRef = useRef(null);
  const rowRefs = useRef([]);

  const rows = useMemo(() => market?.rows || [], [market?.rows]);
  const compare = useCompare();
  const watchlists = useWatchlists();
  const isWatchlistView = channel === "favorites";
  const onlyFav = isWatchlistView || searchParams.get("fav") === "1";
  const watchlistItemKeys = useMemo(() => {
    if (!watchlists.has) return null;
    const keys = [];
    for (const r of rows) {
      if (watchlists.has(r.key)) keys.push(r.key);
    }
    return new Set(keys);
  }, [watchlists, rows]);

  const effectiveWatchlistKeys = onlyFav ? watchlistItemKeys : null;

  // Seller-scan: when ?seller= is active, fetch the seller's item set and
  // use it as a hard filter.
  const { data: sellerItems, loading: sellerScanning, loadingMore: sellerLoadingMore } = useSellerItems(sellerFilter);
  const sellerItemKeys = useMemo(() => {
    if (!sellerItems?.matches) return null;
    return new Set(sellerItems.matches.map((m) => m.itemKey));
  }, [sellerItems]);

  const categories = useMemo(() => {
    const set = new Set();
    rows.forEach((r) => r.category && set.add(r.category));
    return ["", ...Array.from(set).sort()];
  }, [rows]);

  const filtered = useMemo(() => {
    const query = q.trim().toLowerCase();
    const radarFilter = DEAL_RADAR.find((d) => d.id === radar)?.filter;
    let r = rows.filter((row) => {
       if (query) {
         const inName = fuzzySearch(query, row.name);
         const inKey = fuzzySearch(query, row.key);
         const inMods = (row.modifiers || []).some((m) => fuzzySearch(query, m));
         if (!inName && !inKey && !inMods) return false;
       }
       if (category && row.category !== category) return false;
       if (confidence && row.confidence !== confidence) return false;
       if (priceRange[0] > 0 && row.median < priceRange[0]) return false;
       if (priceRange[1] > 0 && row.median > priceRange[1]) return false;
       if (onlyFav && effectiveWatchlistKeys && !effectiveWatchlistKeys.has(row.key)) return false;
       if (radarFilter && !radarFilter(row)) return false;
       if (sellerItemKeys && !sellerItemKeys.has(row.key)) return false;
      return true;
    });
    r.sort((a, b) => {
      let av, bv;
      if (sortKey === "name") {
        av = a.name; bv = b.name;
        return sortDir === "asc" ? av.localeCompare(bv) : bv.localeCompare(av);
      }
      if (sortKey === "dealScore") {
        av = dealScore(a); bv = dealScore(b);
        return sortDir === "asc" ? av - bv : bv - av;
      }
      if (sortKey === "lastSeen") {
        av = a.lastSeenMs ?? 0;
        bv = b.lastSeenMs ?? 0;
        return sortDir === "asc" ? av - bv : bv - av;
      }
      av = a[sortKey] ?? 0;
      bv = b[sortKey] ?? 0;
      return sortDir === "asc" ? av - bv : bv - av;
    });
    return r;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [rows, q, category, confidence, sortKey, sortDir, onlyFav, radar, watchlists.count, sellerItemKeys, effectiveWatchlistKeys]);

  const totalPages = Math.max(1, Math.ceil(filtered.length / PAGE_SIZE));
  const safePage = Math.min(page, totalPages);
  const start = (safePage - 1) * PAGE_SIZE;
  const visible = filtered.slice(start, start + PAGE_SIZE);

  // Reset cursor when visible list changes
  useEffect(() => { setCursor(0); }, [q, category, confidence, sortKey, sortDir, onlyFav, radar, sellerFilter, safePage]);

  // Keep the cursor row visible inside the scrollable container.
  useEffect(() => {
    const el = rowRefs.current[cursor];
    if (!el) return;
    el.scrollIntoView({ block: "nearest", behavior: "smooth" });
  }, [cursor]);

  // Keyboard navigation: j/k/f/c/enter/`/`
  useEffect(() => {
    const handler = (e) => {
      const tag = (document.activeElement?.tagName || "").toLowerCase();
      const isTyping = tag === "input" || tag === "textarea" || tag === "select";
      if (e.key === "/" && !isTyping) {
        e.preventDefault();
        searchRef.current?.focus();
        return;
      }
      if (isTyping) return;
      if (e.metaKey || e.ctrlKey || e.altKey) return;
      const row = visible[cursor];
      if (e.key === "j" || e.key === "ArrowDown") {
        e.preventDefault();
        setCursor((c) => {
          const newCursor = Math.min(visible.length - 1, c + 1);
          rowRefs.current[newCursor]?.scrollIntoView({ block: "nearest" });
          return newCursor;
        });
      } else if (e.key === "k" || e.key === "ArrowUp") {
        e.preventDefault();
        setCursor((c) => {
          const newCursor = Math.max(0, c - 1);
          rowRefs.current[newCursor]?.scrollIntoView({ block: "nearest" });
          return newCursor;
        });
      } else if (e.key === "Enter" && row) {
        e.preventDefault();
        openItem(searchParams, setSearchParams, row.key);
      } else if (e.key === "f" && row) {
        e.preventDefault();
        watchlists.toggle(row.key);
      } else if (e.key === "c" && row) {
        e.preventDefault();
        const res = compare.add(row.key);
        if (res.full) toast.error(`Compare full (${compare.max} max)`);
      }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [visible, cursor, searchParams]);

  const setSort = (k) => {
    if (sortKey === k) setSortDir((d) => (d === "asc" ? "desc" : "asc"));
    else { setSortKey(k); setSortDir("desc"); }
    setPage(1);
  };

  const handleFav = (e, key) => { e.preventDefault(); e.stopPropagation(); watchlists.toggle(key); };
  const handleCompare = (e, key) => {
    e.preventDefault(); e.stopPropagation();
    const res = compare.add(key);
    if (res.full) toast.error(`Compare list is full (${compare.max} items max)`);
  };

  const updateParam = (k, v) => {
    const next = new URLSearchParams(searchParams);
    if (v === null || v === "" || v === false) next.delete(k);
    else next.set(k, v);
    setSearchParams(next);
  };

  // True when any filter/search is narrowing the table.
  // Default state: sortKey="lastSeen", sortDir="desc" — not counted as "active filter".
  const hasActiveFilters = !!(
    q || category || confidence || (priceRange[0] > 0 || priceRange[1] > 0)
    || sortKey !== "lastSeen" || sortDir !== "desc"
    || sellerFilter || onlyFav || radar
  );
  const clearAllFilters = () => {
    setQ(""); setCategory(""); setConfidence("");
    setPriceRange([0, 0]);
    setSortKey("lastSeen"); setSortDir("desc");
    setPage(1);
    setSearchParams({});
  };

  return (
    <div data-testid="listings-page" className="min-h-screen bg-bg-base text-white font-body">
      <Header />
      <main className="pt-32 pb-24">
        <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
          <Reveal>
            <div className="font-mono text-[11px] uppercase tracking-[0.25em] text-emerald-400 mb-4">/ Auction Listings</div>
            <h1 className="font-heading text-5xl sm:text-6xl lg:text-7xl tracking-tighter font-black leading-[0.95]">
              All <span className="text-emerald-400 tabular">{market?.stats.totalItems || rows.length}</span> items.<br />
              Live medians.
            </h1>
            <p className="mt-6 text-zinc-400 max-w-2xl text-lg">
              Search, filter and sort every auction-house item. Tap any row — the detail panel opens instantly,
              no page reload. Try <span className="inline-flex items-center gap-1"><span className="kbd">{CMD_KEY_CHIP}</span><span className="kbd">k</span></span> or <span className="kbd">/</span> to search anywhere · <span className="kbd">?</span> for shortcuts.
            </p>
          </Reveal>

          <RecentlyViewed max={7} compact />

          <StaleDataBanner />
          <OfflineBanner />

          {sellerFilter && <SellerHint seller={sellerFilter} sellerData={sellers?.find((s) => s.name === sellerFilter)} scanning={sellerScanning} loadingMore={sellerLoadingMore} scanned={sellerItems?.scanned} limit={sellerItems?.limit} hasMore={sellerItems?.hasMore} matchCount={sellerItems?.matchCount} totalListings={sellerItems?.matches?.reduce((s,m)=>s+m.listingCount,0)} latestSeenMs={sellerItems?.matches?.reduce((mx,m)=>Math.max(mx,m.latestSeenMs||0),0)} onLoadMore={sellerItems?.loadMore} onOpenSeller={(name) => navigate(`/sellers/${encodeURIComponent(name)}`)} onClear={() => updateParam("seller", "")} />}

          {/* Stat strip */}
          <Reveal delay={0.1} className="mt-10">
            <div className="grid grid-cols-2 md:grid-cols-4 gap-px bg-white/10 border border-white/10 rounded-lg overflow-hidden">
              {[
                { l: "Total items", v: market?.stats.totalItems ?? "—" },
                { l: "Showing", v: filtered.length },
                { l: "Favorites", v: watchlists.count },
                { l: "Last updated", v: market?.stats.lastUpdated ?? "—" },
              ].map((s) => (
                <div key={s.l} className="bg-bg-base/80 px-6 py-5">
                  <div className="font-mono text-[10px] uppercase tracking-[0.25em] text-zinc-500 mb-2">{s.l}</div>
                  <div className="font-heading font-extrabold text-2xl text-white tabular">{s.v}</div>
                </div>
              ))}
            </div>
            {market?.stats?.lastUpdatedMs > 0 && (
              <div className="mt-3 flex items-center gap-3">
                <FreshnessPill ms={market.stats.lastUpdatedMs} prefix="Market" />
                <span className="font-mono text-[10px] uppercase tracking-[0.18em] text-zinc-600">
                  Snapshot of {market.stats.totalItems} items
                </span>
              </div>
            )}
          </Reveal>

          {/* Deal Radar — horizontally scrollable on mobile so 7 chips
              don't blow up the viewport, full wrap on desktop. The
              gradient mask on the right hints at overflow. */}
          <div className="mt-8 md:-mx-6 md:px-6 overflow-x-auto no-scrollbar [mask-image:linear-gradient(to_right,black_calc(100%-3rem),transparent)] md:[mask-image:none]">
            <div className="flex md:flex-wrap gap-2 w-max md:w-auto">
              <span className="inline-flex items-center text-[10px] font-mono uppercase tracking-[0.25em] text-zinc-500 mr-1 shrink-0">Deal radar ·</span>
              {DEAL_RADAR.map((d) => {
                const Icon = d.icon;
                const active = radar === d.id;
                const colorMap = {
                  emerald: active ? "bg-emerald-500/15 border-emerald-500/40 text-emerald-300" : "border-white/10 hover:border-emerald-500/40 hover:text-emerald-300",
                  red:     active ? "bg-red-500/15 border-red-500/40 text-red-300" : "border-white/10 hover:border-red-500/40 hover:text-red-300",
                  amber:   active ? "bg-amber-500/15 border-amber-500/40 text-amber-300" : "border-white/10 hover:border-amber-500/40 hover:text-amber-300",
                };
                return (
                  <button
                    key={d.id}
                    data-testid={`radar-${d.id}`}
                    onClick={() => updateParam("r", active ? "" : d.id)}
                    className={`inline-flex items-center gap-1.5 border rounded-full px-3 py-1.5 font-mono text-[11px] uppercase tracking-wider text-white transition-all shrink-0 ${colorMap[d.color]}`}
                  >
                    <Icon className="w-3 h-3" /> {d.label}
                  </button>
                );
              })}
            </div>
          </div>

          {/* Toolbar */}
          <div className="mt-6 flex flex-col lg:flex-row gap-4 items-stretch lg:items-center justify-between">
            <div className="relative flex-1 max-w-xl">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-500" />
              <input
                ref={searchRef}
                data-testid="listings-search"
                type="text"
                value={q}
                onChange={(e) => { setQ(e.target.value); setPage(1); }}
                placeholder="Search items — Prismatic, Book: Mending, Knowledge Cap [Farming]…"
                aria-label="Search items"
                className="w-full bg-white/[0.03] border border-white/10 focus:border-emerald-500 rounded-lg pl-11 pr-12 py-3 text-white placeholder-zinc-600 outline-none transition-colors font-body"
              />
              <span className="absolute right-3 top-1/2 -translate-y-1/2 kbd">/</span>
            </div>
            <div className="flex gap-3 flex-wrap">
              <select data-testid="filter-category" value={category} onChange={(e) => { setCategory(e.target.value); setPage(1); }}
                aria-label="Filter by category"
                className="bg-white/[0.03] border border-white/10 focus:border-emerald-500 rounded-lg px-4 py-3 text-white outline-none cursor-pointer font-mono text-xs uppercase tracking-wider">
                {categories.map((c) => (<option key={c} value={c} className="bg-bg-base">{c || "All categories"}</option>))}
              </select>
               <select data-testid="filter-confidence" value={confidence} onChange={(e) => { setConfidence(e.target.value); setPage(1); }}
                 aria-label="Filter by confidence level"
                 className="bg-white/[0.03] border border-white/10 focus:border-emerald-500 rounded-lg px-4 py-3 text-white outline-none cursor-pointer font-mono text-xs uppercase tracking-wider">
                 <option value="" className="bg-bg-base">All confidence</option>
                 <option value="high" className="bg-bg-base">High</option>
                 <option value="good" className="bg-bg-base">Good</option>
                 <option value="fair" className="bg-bg-base">Fair</option>
                 <option value="low" className="bg-bg-base">Low</option>
                 <option value="unreliable" className="bg-bg-base">Unreliable</option>
               </select>
               <div className="flex items-center gap-2 bg-white/[0.03] border border-white/10 rounded-lg px-4 py-3 text-white font-mono text-xs uppercase tracking-wider">
                 <span>Price:</span>
                 <input
                   type="number"
                   min="0"
                   placeholder="Min"
                   value={priceRange[0] || ""}
                   onChange={(e) => {
                     const value = parseInt(e.target.value) || 0;
                     setPriceRange([value, priceRange[1]]);
                     setPage(1);
                   }}
                   className="w-16 bg-transparent outline-none text-right"
                 />
                 <span>—</span>
                 <input
                   type="number"
                   min="0"
                   placeholder="Max"
                   value={priceRange[1] || ""}
                   onChange={(e) => {
                     const value = parseInt(e.target.value) || 0;
                     setPriceRange([priceRange[0], value]);
                     setPage(1);
                   }}
                   className="w-16 bg-transparent outline-none text-right"
                 />
               </div>
              <button
                data-testid="toggle-fav-only"
                onClick={() => updateParam("fav", onlyFav ? "" : "1")}
                className={`inline-flex items-center gap-2 border rounded-lg px-4 py-3 font-mono text-xs uppercase tracking-wider transition-colors ${
                  onlyFav ? "bg-amber-500/10 border-amber-500/40 text-amber-300" : "bg-white/[0.03] border-white/10 text-white hover:border-white/30"
                }`}
              >
                <Star className={`w-3.5 h-3.5 ${onlyFav ? "fill-amber-300" : ""}`} /> Favs
              </button>
              {watchlists.count > 0 && (
                <select
                  data-testid="watchlist-selector"
                  value={watchlists.currentId}
                  onChange={(e) => watchlists.switchList(e.target.value)}
                  className="bg-white/[0.03] border border-white/10 focus:border-amber-500 rounded-lg px-3 py-3 text-xs font-mono uppercase tracking-wider text-amber-300 outline-none cursor-pointer"
                >
                  {watchlists.lists.map(l => (
                    <option key={l.id} value={l.id} className="bg-bg-base">{l.name}</option>
                  ))}
                </select>
              )}
            </div>
          </div>

          <div className="mt-6 hidden md:flex flex-wrap items-center gap-3 font-mono text-[10px] uppercase tracking-wider text-zinc-500">
            <span>Shortcuts ·</span>
            <span className="inline-flex items-center gap-1.5"><span className="inline-flex items-center gap-0.5"><span className="kbd">↑</span><span className="kbd">↓</span></span> nav</span>
            <span className="inline-flex items-center gap-1.5"><span className="kbd">↵</span> open</span>
            <span className="inline-flex items-center gap-1.5"><span className="kbd">f</span> fav</span>
            <span className="inline-flex items-center gap-1.5"><span className="kbd">c</span> compare</span>
            <span className="inline-flex items-center gap-1.5"><span className="kbd">/</span> search</span>
            <span className="inline-flex items-center gap-1.5"><span className="inline-flex items-center gap-0.5"><span className="kbd">{CMD_KEY_CHIP}</span><span className="kbd">k</span></span> palette</span>
            <span className="text-zinc-700">·</span>
            <span className="text-zinc-700">vim: j/k also work</span>
          </div>

          {/* Active filter chips + top paginator. Sits between shortcuts
              and the table so it's always in view on narrower viewports. */}
          {(sellerFilter || onlyFav || radar || q || category || confidence) && (
            <div className="mt-4 flex flex-wrap gap-2">
              {q && (
                <button onClick={() => setQ("")} className="inline-flex items-center gap-2 bg-emerald-500/10 border border-emerald-500/30 text-emerald-300 rounded-full px-3 py-1.5 font-mono text-[11px] uppercase tracking-wider hover:bg-emerald-500/20 transition-colors">
                  Search: "{q}" <X className="w-3 h-3" />
                </button>
              )}
              {category && (
                <button onClick={() => { setCategory(""); setPage(1); }} className="inline-flex items-center gap-2 bg-emerald-500/10 border border-emerald-500/30 text-emerald-300 rounded-full px-3 py-1.5 font-mono text-[11px] uppercase tracking-wider hover:bg-emerald-500/20 transition-colors">
                  Category: {category} <X className="w-3 h-3" />
                </button>
              )}
               {confidence && (
                 <button onClick={() => { setConfidence(""); setPage(1); }} className="inline-flex items-center gap-2 bg-emerald-500/10 border border-emerald-500/30 text-emerald-300 rounded-full px-3 py-1.5 font-mono text-[11px] uppercase tracking-wider hover:bg-emerald-500/20 transition-colors">
                   Confidence: {confidence} <X className="w-3 h-3" />
                 </button>
               )}
               {(priceRange[0] > 0 || priceRange[1] > 0) && (
                 <button onClick={() => { setPriceRange([0, 0]); setPage(1); }} className="inline-flex items-center gap-2 bg-emerald-500/10 border border-emerald-500/30 text-emerald-300 rounded-full px-3 py-1.5 font-mono text-[11px] uppercase tracking-wider hover:bg-emerald-500/20 transition-colors">
                   Price: {priceRange[0] > 0 ? `≥${fmt(priceRange[0])}` : ""} {priceRange[0] > 0 && priceRange[1] > 0 ? "—" : ""} {priceRange[1] > 0 ? `≤${fmt(priceRange[1])}` : ""} <X className="w-3 h-3" />
                 </button>
               )}
              {sellerFilter && (
                <button onClick={() => updateParam("seller", "")} className="inline-flex items-center gap-2 bg-emerald-500/10 border border-emerald-500/30 text-emerald-300 rounded-full px-3 py-1.5 font-mono text-[11px] uppercase tracking-wider hover:bg-emerald-500/20 transition-colors">
                  Seller: {sellerFilter} <X className="w-3 h-3" />
                </button>
              )}
              {channel === "favorites" && (
                <div className="inline-flex items-center gap-1">
                  <div className="inline-flex items-center gap-1.5 bg-amber-500/10 border border-amber-500/30 text-amber-300 rounded-full pl-3 pr-2 py-1.5 font-mono text-[11px] uppercase tracking-wider">
                    <Star className="w-3 h-3 fill-amber-300" /> Channel: Favorites <X className="w-3 h-3" />
                  </div>
                  <Link
                    to="/favorites"
                    data-testid="listings-view-fav-page"
                    className="inline-flex items-center gap-1 text-amber-300 hover:text-amber-200 font-mono text-[10px] uppercase tracking-wider px-2 py-1.5 transition-colors"
                  >
                    View page <ArrowUpRight className="w-3 h-3" />
                  </Link>
                </div>
              )}
              {onlyFav && channel !== "favorites" && (
                <div className="inline-flex items-center gap-1">
                  <button onClick={() => updateParam("fav", "")} className="inline-flex items-center gap-2 bg-amber-500/10 border border-amber-500/30 text-amber-300 rounded-full pl-3 pr-2 py-1.5 font-mono text-[11px] uppercase tracking-wider hover:bg-amber-500/20 transition-colors">
                    <Star className="w-3 h-3 fill-amber-300" /> Favorites only <X className="w-3 h-3" />
                  </button>
                  <Link
                    to="/favorites"
                    data-testid="listings-view-fav-page"
                    className="inline-flex items-center gap-1 text-amber-300 hover:text-amber-200 font-mono text-[10px] uppercase tracking-wider px-2 py-1.5 transition-colors"
                  >
                    View page <ArrowUpRight className="w-3 h-3" />
                  </Link>
                </div>
              )}
              {radar && (
                <button onClick={() => updateParam("r", "")} className="inline-flex items-center gap-2 bg-white/[0.04] border border-white/10 text-white rounded-full px-3 py-1.5 font-mono text-[11px] uppercase tracking-wider hover:bg-white/[0.08] transition-colors">
                  {DEAL_RADAR.find(d => d.id === radar)?.label} <X className="w-3 h-3" />
                </button>
              )}
              {hasActiveFilters && (
                <button
                  onClick={clearAllFilters}
                  data-testid="listings-clear-all"
                  className="inline-flex items-center gap-1.5 border border-white/10 hover:border-red-500/40 hover:text-red-400 text-zinc-400 font-bold uppercase tracking-[0.18em] text-[10px] px-3 py-1.5 rounded-full transition-colors"
                >
                  <X className="w-3 h-3" /> Clear all filters
                </button>
              )}
            </div>
          )}

          {/* Top paginator: only renders when there's more than one page */}
          {!loading.market && filtered.length > PAGE_SIZE && (
            <div className="mt-4 flex items-center justify-between px-1 py-1 font-mono text-xs">
              <span className="text-zinc-500">Page {safePage} of {totalPages} · <span className="tabular">{filtered.length}</span> results</span>
              <div className="flex gap-2">
                <button data-testid="page-prev-top" onClick={() => setPage((p) => Math.max(1, p - 1))} disabled={safePage === 1} className="px-3 py-1.5 border border-white/15 rounded hover:border-emerald-500 hover:text-emerald-400 disabled:opacity-30 disabled:cursor-not-allowed transition-colors">← Prev</button>
                <button data-testid="page-next-top" onClick={() => setPage((p) => Math.min(totalPages, p + 1))} disabled={safePage === totalPages} className="px-3 py-1.5 border border-white/15 rounded hover:border-emerald-500 hover:text-emerald-400 disabled:opacity-30 disabled:cursor-not-allowed transition-colors">Next →</button>
              </div>
            </div>
          )}

          {error.market && (
            <div className="mt-6 inline-flex items-center gap-2 bg-amber-500/10 border border-amber-500/30 text-amber-300 rounded-lg px-4 py-2 font-mono text-xs">
              <AlertTriangle className="w-4 h-4" /> {error.market} · showing cached data
            </div>
          )}

          <div className="mt-8 bg-bg-deeper border border-white/10 rounded-2xl overflow-hidden">
            {/* Desktop table */}
            <div className="overflow-x-hidden hidden md:block">
              <table className="w-full text-sm">
                <thead>
                  <tr className="text-left font-mono text-[10px] uppercase tracking-[0.2em] text-zinc-500 border-b border-white/10">
                    <th className="px-4 py-4 text-center"><span className="inline-flex p-1.5"><Star className="w-4 h-4 text-transparent" /></span></th>
                    <ThSort label="Item" k="name" sortKey={sortKey} sortDir={sortDir} onClick={setSort} />
                    <th className="px-4 py-4 text-left font-medium">Category</th>
                    <ThSort label="Median" k="median" sortKey={sortKey} sortDir={sortDir} onClick={setSort} align="right" />
                    <th className="px-4 py-4 text-left font-medium hidden lg:table-cell">IQR</th>
                    <th className="px-4 py-4 text-left font-medium">Conf.</th>
                    <th className="px-4 py-4 text-left font-medium">Trend</th>
                    <ThSort label="Last seen" k="lastSeen" sortKey={sortKey} sortDir={sortDir} onClick={setSort} align="right" />
                    <ThSort label="Samples" k="samples" sortKey={sortKey} sortDir={sortDir} onClick={setSort} align="right" />
                    <th className="px-4 py-4 text-right"></th>
                  </tr>
                </thead>
                <tbody>
                  {loading.market
                    ? Array.from({ length: 12 }).map((_, i) => (
                        <tr key={i} className="border-b border-white/5"><td className="px-4 py-4" colSpan={10}><div className="h-4 bg-white/5 rounded animate-pulse" /></td></tr>
                      ))
                    : sellerFilter && sellerScanning
                      ? Array.from({ length: 12 }).map((_, i) => (
                          <tr key={i} className="border-b border-white/5"><td className="px-4 py-4" colSpan={10}><div className="h-4 bg-white/5 rounded animate-pulse" /></td></tr>
                        ))
                      : visible.length === 0
                        ? (<tr><td colSpan={10} className="px-4 py-16 text-center text-zinc-500 font-mono text-xs uppercase tracking-wider">No items match your filters.</td></tr>)
                        : visible.map((r, i) => {
                          const isFav = watchlists.has(r.key);
                          const inCompare = compare.has(r.key);
                          const isCursor = cursor === i;
                          return (
                             <tr
                               key={r.key}
                               ref={(el) => { rowRefs.current[i] = el; }}
                               data-testid={`listing-row-${i}`}
                               data-cursor={isCursor ? "true" : undefined}
                               onClick={() => openItem(searchParams, setSearchParams, r.key)}
                               onKeyDown={(e) => { if (e.key === "Enter" || e.key === " ") { e.preventDefault(); openItem(searchParams, setSearchParams, r.key); } }}
                               onMouseEnter={() => setCursor(i)}
                               tabIndex={0}
                               role="link"
                               className={`border-b border-white/5 last:border-0 transition-colors group cursor-pointer ${isCursor ? "bg-emerald-500/[0.08] outline outline-1 -outline-offset-1 outline-emerald-500/40" : "hover:bg-white/[0.03]"}`}
                             >
                              <td className="px-4 py-4">
                                <button onClick={(e) => handleFav(e, r.key)} data-testid={`row-fav-${i}`} aria-label="Toggle favorite" className={`p-1.5 rounded transition-colors ${isFav ? "text-amber-400" : "text-zinc-600 hover:text-amber-400"}`}>
                                  <Star className={`w-4 h-4 ${isFav ? "fill-amber-400" : ""}`} />
                                </button>
                              </td>
                              <td className="px-4 py-4">
                                <span className="font-medium text-white group-hover:text-emerald-400 transition-colors inline-flex items-center gap-2 min-w-0">
                                  <ItemName name={r.name} tier={r.tier} modifiers={r.modifiers} />
                                  {isDeal(r) && (
                                    <span
                                      data-testid={`row-deal-${i}`}
                                      title={`Median is in the bottom 10% of IQR (${fmt(r.iqrLow)}–${fmt(r.iqrHigh)}) — looks cheap vs. recent sales`}
                                      className="shrink-0 inline-flex items-center gap-0.5 bg-orange-500/15 border border-orange-500/40 text-orange-300 font-mono text-[9px] uppercase tracking-[0.15em] px-1.5 py-0.5 rounded-sm"
                                    >
                                      <Flame className="w-2.5 h-2.5" /> Deal
                                    </span>
                                  )}
                                  {isOverpriced(r) && (
                                    <span
                                      data-testid={`row-overpriced-${i}`}
                                      title={`Median is in the top 10% of IQR (${fmt(r.iqrLow)}–${fmt(r.iqrHigh)}) — listing at a premium vs. recent sales`}
                                      className="shrink-0 inline-flex items-center gap-0.5 bg-red-500/15 border border-red-500/40 text-red-300 font-mono text-[9px] uppercase tracking-[0.15em] px-1.5 py-0.5 rounded-sm"
                                    >
                                      <Skull className="w-2.5 h-2.5" /> Overpriced
                                    </span>
                                  )}
                                </span>
                              </td>
                              <td className="px-4 py-4 font-mono text-xs text-zinc-400">{r.category}</td>
                              <td className="px-4 py-4 font-mono text-right text-white tabular"><span className="price-pill">{fmt(r.median)}</span></td>
                              <td className="px-4 py-4 font-mono text-xs text-zinc-400 hidden lg:table-cell tabular">{fmt(r.iqrLow)} — {fmt(r.iqrHigh)}</td>
                              <td className="px-4 py-4 text-center">
                                <span className="inline-flex items-center justify-center gap-1.5 font-mono text-[10px] uppercase tracking-wider text-zinc-400">
                                  <ConfDot conf={r.confidence} /> {r.confidence}
                                </span>
                              </td>
                              <td className="px-4 py-4 text-center"><span className="inline-flex items-center justify-center"><TrendIcon trend={r.trend} /></span></td>
                              <td className="px-4 py-4 font-mono text-right text-zinc-400 tabular">{fmtTime(r.lastSeenMs)}</td>
                              <td className="px-4 py-4 font-mono text-right text-zinc-400 tabular">{r.samples}</td>
                              <td className="px-4 py-4 text-right">
                                <div className="inline-flex gap-1">
                                  <button onClick={(e) => handleCompare(e, r.key)} data-testid={`row-compare-${i}`} aria-label={inCompare ? "Remove from compare" : "Add to compare"} title={inCompare ? "Remove from compare" : "Add to compare"} className={`p-1.5 rounded transition-colors ${inCompare ? "text-emerald-400" : "text-zinc-600 hover:text-emerald-400"}`}>
                                    <GitCompare className="w-4 h-4" />
                                  </button>
                                  <button
                                    onClick={(e) => { e.stopPropagation(); openItem(searchParams, setSearchParams, r.key); }}
                                    data-testid={`row-open-${i}`}
                                    className="p-1.5 rounded text-zinc-600 hover:text-white transition-colors"
                                    aria-label="Open detail"
                                  >
                                    <ArrowUpRight className="w-4 h-4" />
                                  </button>
                                </div>
                              </td>
                            </tr>
                          );
                        })}
                </tbody>
              </table>
            </div>

            {/* Mobile cards */}
            <div className="md:hidden divide-y divide-white/5">
              {loading.market
                ? Array.from({ length: 6 }).map((_, i) => (<div key={i} className="px-5 py-4"><div className="h-5 bg-white/5 rounded animate-pulse" /></div>))
                : sellerFilter && sellerScanning
                  ? Array.from({ length: 6 }).map((_, i) => (<div key={i} className="px-5 py-4"><div className="h-5 bg-white/5 rounded animate-pulse" /></div>))
                  : visible.length === 0
                    ? <div className="px-5 py-12 text-center text-zinc-500 font-mono text-xs uppercase tracking-wider">No items.</div>
                    : visible.map((r, i) => {
                      const isFav = watchlists.has(r.key);
                      const inCompare = compare.has(r.key);
                      const isCursor = cursor === i;
                      return (
                        <div
                          onClick={() => openItem(searchParams, setSearchParams, r.key)}
                          ref={(el) => { rowRefs.current[i] = el; }}
                          key={r.key}
                          data-testid={`listing-mobile-${i}`}
                          data-cursor={isCursor ? "true" : undefined}
                          onMouseEnter={() => setCursor(i)}
                          className={`w-full flex items-center gap-3 px-5 py-4 transition-colors text-left ${isCursor ? "bg-emerald-500/[0.08] outline outline-1 -outline-offset-1 outline-emerald-500/40" : "hover:bg-white/[0.03]"}`}
                        >
                          <button onClick={(e) => handleFav(e, r.key)} aria-label={isFav ? "Remove from favorites" : "Add to favorites"} className={`p-1.5 rounded cursor-pointer ${isFav ? "text-amber-400" : "text-zinc-700 hover:text-amber-400"}`}>
                            <Star className={`w-4 h-4 ${isFav ? "fill-amber-400" : ""}`} />
                          </button>
                          <div className="flex-1 min-w-0">
                            <div className="font-medium text-white truncate flex items-center gap-2 min-w-0">
                              <ItemName name={r.name} tier={r.tier} modifiers={r.modifiers} />
                              {isDeal(r) && (
                                <span
                                  data-testid={`row-deal-${i}`}
                                  title={`Median is in the bottom 10% of IQR (${fmt(r.iqrLow)}–${fmt(r.iqrHigh)}) — looks cheap vs. recent sales`}
                                  className="shrink-0 inline-flex items-center gap-0.5 bg-orange-500/15 border border-orange-500/40 text-orange-300 font-mono text-[9px] uppercase tracking-[0.15em] px-1.5 py-0.5 rounded-sm"
                                >
                                  <Flame className="w-2.5 h-2.5" /> Deal
                                </span>
                              )}
                              {isOverpriced(r) && (
                                <span
                                  data-testid={`row-overpriced-${i}`}
                                  title={`Median is in the top 10% of IQR (${fmt(r.iqrLow)}–${fmt(r.iqrHigh)}) — listing at a premium vs. recent sales`}
                                  className="shrink-0 inline-flex items-center gap-0.5 bg-red-500/15 border border-red-500/40 text-red-300 font-mono text-[9px] uppercase tracking-[0.15em] px-1.5 py-0.5 rounded-sm"
                                >
                                  <Skull className="w-2.5 h-2.5" /> Overpriced
                                </span>
                              )}
                            </div>
                            <div className="flex items-center gap-2 mt-1 font-mono text-[10px] uppercase tracking-wider text-zinc-500">
                              <span>{r.category}</span><span>·</span><ConfDot conf={r.confidence} /><span>{r.confidence}</span><span>·</span><span className="tabular">{r.samples}s</span>
                            </div>
                          </div>
                          <div className="text-right">
                            <div className="font-heading font-bold text-white tabular">{fmt(r.median)}</div>
                            <div className="flex items-center justify-end gap-1.5 mt-1">
                              <TrendIcon trend={r.trend} />
                              <button onClick={(e) => handleCompare(e, r.key)} aria-label={inCompare ? "Remove from compare" : "Add to compare"} className={`p-1 rounded cursor-pointer ${inCompare ? "text-emerald-400" : "text-zinc-600 hover:text-emerald-400"}`}>
                                <GitCompare className="w-3.5 h-3.5" />
                              </button>
                            </div>
                          </div>
                        </div>
                      );
                    })}
            </div>

            {!loading.market && filtered.length > PAGE_SIZE && (
              <div className="flex items-center justify-between px-6 py-5 border-t border-white/10 font-mono text-xs">
                <span className="text-zinc-500">Page {safePage} of {totalPages} · <span className="tabular">{filtered.length}</span> results</span>
                <div className="flex gap-2">
                  <button data-testid="page-prev" onClick={() => setPage((p) => Math.max(1, p - 1))} disabled={safePage === 1} className="px-3 py-1.5 border border-white/15 rounded hover:border-emerald-500 hover:text-emerald-400 disabled:opacity-30 disabled:cursor-not-allowed transition-colors">← Prev</button>
                  <button data-testid="page-next" onClick={() => setPage((p) => Math.min(totalPages, p + 1))} disabled={safePage === totalPages} className="px-3 py-1.5 border border-white/15 rounded hover:border-emerald-500 hover:text-emerald-400 disabled:opacity-30 disabled:cursor-not-allowed transition-colors">Next →</button>
                </div>
              </div>
            )}
          </div>

          <div className="mt-6 flex flex-wrap items-center gap-3 font-mono text-[10px] uppercase tracking-wider text-zinc-500">
            <span className="text-zinc-600">Tip · double-tap <span className="kbd">/</span> to focus search</span>
          </div>

          {loading.market && (
            <div className="mt-6 inline-flex items-center gap-2 text-zinc-500 font-mono text-xs">
              <Loader2 className="w-3.5 h-3.5 animate-spin" /> Loading market data…
            </div>
          )}
        </div>
      </main>
      <Footer />
    </div>
  );
}

function ThSort({ label, k, sortKey, sortDir, onClick, align = "left" }) {
  const active = sortKey === k;
  const onKeyDown = (e) => {
    if (e.key === "Enter" || e.key === " ") {
      e.preventDefault();
      onClick(k);
    }
  };
  return (
    <th
      className={`px-4 py-4 font-medium select-none ${align === "right" ? "text-right" : "text-left"}`}
      onClick={() => onClick(k)}
      onKeyDown={onKeyDown}
      role="button"
      tabIndex={0}
      aria-sort={active ? (sortDir === "asc" ? "ascending" : "descending") : "none"}
      aria-label={`${label}${active ? `, sorted ${sortDir === "asc" ? "ascending" : "descending"}` : ""}`}
    >
      <span className={`${active ? "text-emerald-400" : ""} inline-flex items-center gap-1`}>
        {label} {active && <span>{sortDir === "asc" ? "↑" : "↓"}</span>}
      </span>
    </th>
  );
}

const SELLER_LABEL_STYLES = {
  Trustworthy: { icon: ShieldCheck, color: "text-emerald-400", bg: "bg-emerald-500/10", border: "border-emerald-500/30" },
  Neutral:     { icon: Shield,      color: "text-zinc-400",    bg: "bg-white/[0.04]",    border: "border-white/10" },
  Suspicious:  { icon: ShieldAlert, color: "text-amber-400",   bg: "bg-amber-500/10",   border: "border-amber-500/30" },
  Flagged:     { icon: ShieldX,     color: "text-red-400",     bg: "bg-red-500/10",     border: "border-red-500/30" },
};

function SellerHint({ seller, sellerData, scanning, loadingMore, scanned, limit, hasMore, matchCount, totalListings, latestSeenMs, onLoadMore, onOpenSeller, onClear }) {
  const label = sellerData?.isBlacklisted ? "Flagged" : (sellerData?.accuracyLabel || null);
  const style = label ? SELLER_LABEL_STYLES[label] : null;
  const Icon = style?.icon;
  const allTimeTotal = sellerData?.totalListings;
  // If we know the all-time total and we're showing only the first page,
  // surface "Latest 100 of N" so the cap isn't a silent surprise.
  const capMessage = !scanning && hasMore && allTimeTotal && allTimeTotal > (scanned || 0)
    ? `Latest ${scanned} of ${allTimeTotal} auction-house listings`
    : !scanning && hasMore
      ? `Latest ${scanned || limit || 100} listings · more available`
      : !scanning && scanned > 0
        ? `${scanned} latest listings · complete`
        : null;
  return (
    <div className="w-full bg-emerald-500/10 border border-emerald-500/20 rounded-2xl p-5 mt-4 [transform:translateZ(0)]">
      <div className="flex items-start gap-3">
        <img src={`https://render.crafty.gg/3d/bust/${encodeURIComponent(seller)}`} alt="" width={44} height={44}
          className="rounded-sm bg-white/[0.05] shrink-0"
          onError={(e) => { e.currentTarget.style.visibility = "hidden"; }} />
        <div className="flex-1 min-w-0">
          <div className="font-heading text-lg font-bold flex items-center gap-2 flex-wrap">
            <span className="truncate">{seller}</span>
            {style && Icon && (
              <span className={`inline-flex items-center gap-1 ${style.bg} ${style.border} border rounded-full px-2 py-0.5`}>
                <Icon className={`w-3 h-3 ${style.color}`} />
                <span className={`font-mono text-[10px] uppercase tracking-wider ${style.color}`}>{label}</span>
              </span>
            )}
            {scanning ? (
              <span className="inline-flex items-center gap-1.5 font-mono text-[10px] uppercase tracking-wider text-amber-300">
                <Loader2 className="w-3 h-3 animate-spin" /> Loading latest seller listings…
              </span>
            ) : (
              <span className="font-mono text-[10px] uppercase tracking-wider text-emerald-300">
                {matchCount ?? 0} items · {totalListings ?? 0} listings
                {capMessage && <span className="text-zinc-500"> · {capMessage}</span>}
              </span>
            )}
          </div>
          <p className="mt-1 text-zinc-400 text-sm leading-relaxed">
            {scanning
              ? "Fetching this seller's latest 100 auction-house listings. Cached for 5 min after the first load."
              : matchCount === 0
                ? "No matching listings found in this seller's latest tracked auction-house rows."
                : "Showing only items where this seller currently has listings. Tap any item to see their unit prices in the trail."}
          </p>
          {latestSeenMs > 0 && !scanning && (
            <div className="mt-2 font-mono text-[10px] uppercase tracking-wider text-zinc-500 inline-flex items-center gap-1.5">
              <Clock className="w-3 h-3" /> Latest listing {fmtTime(latestSeenMs)}
            </div>
          )}
          {hasMore && !scanning && (
            <div className="mt-3">
              <button
                data-testid="seller-hint-load-more"
                onClick={onLoadMore}
                disabled={loadingMore}
                className="inline-flex items-center gap-1.5 border border-emerald-500/40 hover:border-emerald-400 hover:bg-emerald-500/10 text-emerald-300 font-bold uppercase tracking-[0.18em] text-[10px] px-3 py-1.5 rounded-sm transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {loadingMore
                  ? <><Loader2 className="w-3 h-3 animate-spin" /> Loading…</>
                  : <>Load next {limit || 100} listings</>}
              </button>
            </div>
          )}
        </div>
        <div className="flex flex-col gap-2 shrink-0">
          {onOpenSeller && sellerData && (
            <button
              data-testid="seller-hint-view-details"
              onClick={() => onOpenSeller(seller)}
              className="inline-flex items-center gap-1.5 bg-white/[0.04] hover:bg-white/[0.08] border border-white/10 hover:border-white/20 text-white font-bold uppercase tracking-[0.18em] text-[10px] px-3 py-1.5 rounded-sm transition-colors"
            >
              View details <ArrowUpRight className="w-3 h-3" />
            </button>
          )}
          {onClear && (
            <button
              data-testid="seller-hint-clear"
              onClick={onClear}
              className="inline-flex items-center gap-1.5 border border-white/10 hover:border-red-500/40 hover:text-red-400 text-zinc-300 font-bold uppercase tracking-[0.18em] text-[10px] px-3 py-1.5 rounded-sm transition-colors"
            >
              <X className="w-3 h-3" /> Clear filter
            </button>
          )}
        </div>
      </div>
    </div>
  );
}
